@theme {
  --color-primary: oklch(0.55 0.17 160);
  --color-primary-hover: oklch(0.48 0.17 160);
  --color-primary-foreground: oklch(0.98 0 0);
  --color-muted: oklch(0.88 0.06 160);
  --color-border: oklch(0.7 0.12 160);
  --color-ring: oklch(0.6 0.15 160);
  --color-surface: oklch(1 0 0);

  --radius-sm: 0;
  --radius-default: 0;
  --radius-lg: 0;
}
